                self.push_eval(wrap24(a % b));
            }
            0x15 => {
                let a = self.pop_eval();
                self.push_eval(wrap24(-a));
            }
            0x16 => {
                let b = self.pop_eval();
                let a = self.pop_eval();
                self.push_eval(wrap24(a & b));
            }
            0x17 => {
                let b = self.pop_eval();
                let a = self.pop_eval();
                self.push_eval(wrap24(a | b));
            }
            0x18 => {
                let b = self.pop_eval();
                let a = self.pop_eval();
                self.push_eval(wrap24(a ^ b));
