}

pub struct TickResult {
    pub done: bool,
}

#[cfg(test)]
mod tests {
    use super::*;

    fn run_to_done(src: &str) -> Session {
        let mut s = Session::new(src);
        for _ in 0..1000 {
            let r = s.tick();
            if r.done {
                break;
            }
        }
        s
    }

    #[test]
    fn hello_runs() {
        let src = include_str!("../examples/hello.bas");
        let s = run_to_done(src);
        eprintln!("status={} trap={} instrs={}", s.status, s.trap_code, s.instruction_count);
        eprintln!("output={:?}", s.stdout_buf);
        assert!(s.is_done(), "did not finish");
        assert!(s.is_halted(), "trapped: {}", s.stop_reason());
        assert!(s.stdout_buf.contains("HELLO WORLD"), "no hello: {:?}", s.stdout_buf);
    }
}

